87	    /// Load the pre-assembled APL binary and start the emulator.
88	    fn load_apl_binary(&mut self) {
89	        let binary = config::APL_BINARY;
90	        self.emulator.hard_reset();
91	        self.emulator.set_uart_tx_busy_cycles(0);
92	        self.emulator.load_program(0, binary);
93	        self.emulator.load_program_extent(binary.len() as u32);
94	        self.emulator.set_pc(0);
95	        self.emulator.resume();
96	        self.running = true;
97	        self.halted = false;
98	        self.output.clear();
99	        self.partial_line.clear();
100	        self.uart_rx_queue.clear();
101	        self.last_tx = None;
102	        self.last_rx = None;
103	    }
