106	    fn feed_uart_bytes(&mut self) {
107	        while !self.uart_rx_queue.is_empty() {
108	            let status = self.emulator.read_byte(0xFF0101);
109	            if status & 0x01 != 0 {
110	                break; // RX buffer full, try again next tick
111	            }
