123	            return;
124	        }
125	        let uart = uart.to_string();
126	        self.emulator.clear_uart_output();
127	
128	        // Track last TX byte
129	        if let Some(b) = uart.bytes().last() {
130	            self.last_tx = Some(b);
131	        }
132	
133	        // Split on newlines, handling partial lines across ticks.
134	        for ch in uart.chars() {
135	            if ch == '\n' {
136	                self.output.push(std::mem::take(&mut self.partial_line));
137	            } else if ch != '\r' {
138	                self.partial_line.push(ch);
139	            }
140	        }
