174	            let trimmed = line.trim();
175	            if trimmed.is_empty() {
176	                continue;
177	            }
178	            for b in trimmed.bytes() {
179	                self.uart_rx_queue.push_back(b);
180	            }
181	            self.uart_rx_queue.push_back(b'\n');
