187	    type Message = Msg;
188	    type Properties = ReplPanelProps;
189	
190	    fn create(ctx: &Context<Self>) -> Self {
191	        ctx.link().send_message(Msg::Init);
192	        let mut emulator = EmulatorCore::new();
193	        emulator.set_uart_tx_busy_cycles(0);
194	        Self {
195	            emulator,
196	            output: vec!["APL / COR24 Environment".to_string(), String::new()],
197	            input: String::new(),
198	            running: false,
199	            halted: false,
200	            uart_rx_queue: VecDeque::new(),
201	            partial_line: String::new(),
202	            _tick_handle: None,
203	            output_ref: NodeRef::default(),
204	            panel_ref: NodeRef::default(),
205	            needs_focus: false,
206	            last_reset_seq: 0,
207	            last_feed_seq: 0,
208	            last_tx: None,
209	            last_rx: None,
210	            history: Vec::new(),
211	            history_index: None,
212	            history_saved_input: String::new(),
213	        }
214	    }
215	
216	    fn changed(&mut self, ctx: &Context<Self>, _old_props: &Self::Properties) -> bool {
217	        let props = ctx.props();
218	
219	        // Handle reset command
220	        if props.reset_seq != self.last_reset_seq {
221	            self.last_reset_seq = props.reset_seq;
222	            self.load_apl_binary();
223	            self.needs_focus = true;
224	            // Always schedule a fresh tick — the old Timeout may have
225	            // already fired (e.g. after )OFF halt) but still be Some.
226	            self._tick_handle = Some(Self::schedule_tick(ctx));
227	        }
228	
229	        // Handle feed text command
230	        if props.feed_seq != self.last_feed_seq {
231	            self.last_feed_seq = props.feed_seq;
232	            self.feed_program_text(&props.feed_text);
233	            self.needs_focus = true;
234	        }
235	
236	        // S2 switch — use emulator API (active-low hardware)
237	        self.emulator.set_button_pressed(props.s2_on);
238	
239	        true
240	    }
241	
242	    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
243	        match msg {
244	            Msg::Init => {
245	                self.load_apl_binary();
246	                self._tick_handle = Some(Self::schedule_tick(ctx));
247	                true
248	            }
249	            Msg::Tick => {
250	                if !self.running || self.halted {
251	                    return false;
252	                }
253	
254	                self.feed_uart_bytes();
255	                let result = self.emulator.run_batch(BATCH_SIZE);
256	                self.collect_uart();
257	
258	                if matches!(result.reason, StopReason::Halted) {
259	                    self.halted = true;
260	                    self.running = false;
261	                    // Flush any remaining partial line
262	                    if !self.partial_line.is_empty() {
263	                        self.output.push(std::mem::take(&mut self.partial_line));
264	                    }
265	                    self.output.push(String::new());
266	                    self.output
267	                        .push("[Halted — press Reset to restart]".to_string());
268	                }
269	
270	                if self.running && !self.halted {
271	                    self._tick_handle = Some(Self::schedule_tick(ctx));
272	                }
273	
274	                // Report hardware state to parent (LED is active-low)
275	                let led_on = self.emulator.is_led_on();
276	                ctx.props()
277	                    .on_hw_state
278	                    .emit((led_on, self.last_tx, self.last_rx));
279	
280	                true
281	            }
282	            Msg::KeyDown(e) => {
283	                // Let modifier combos (Cmd-C, Ctrl-V, etc.) pass through to browser
284	                if e.meta_key() || e.ctrl_key() || e.alt_key() {
285	                    return false;
286	                }
287	                // Ignore input when the emulator has halted (e.g. after )OFF)
288	                if self.halted {
289	                    return false;
290	                }
291	                let key = e.key();
292	                match key.as_str() {
293	                    "Enter" => {
294	                        e.prevent_default();
295	                        // Show the input line in output
296	                        let line = format!("{PROMPT}{}", self.input);
297	                        self.output.push(line);
298	                        // Queue input bytes for the emulator's UART
299	                        for b in self.input.bytes() {
300	                            self.uart_rx_queue.push_back(b);
301	                        }
302	                        self.uart_rx_queue.push_back(b'\n');
303	                        // Save non-empty input to history
304	                        if !self.input.is_empty() {
305	                            self.history.push(self.input.clone());
306	                        }
307	                        self.input.clear();
308	                        self.history_index = None;
309	                        true
310	                    }
311	                    "ArrowUp" => {
312	                        e.prevent_default();
313	                        if self.history.is_empty() {
314	                            return false;
315	                        }
316	                        let new_index = match self.history_index {
317	                            None => {
318	                                self.history_saved_input = self.input.clone();
319	                                self.history.len() - 1
320	                            }
321	                            Some(0) => return false,
322	                            Some(i) => i - 1,
323	                        };
324	                        self.history_index = Some(new_index);
325	                        self.input = self.history[new_index].clone();
326	                        true
327	                    }
328	                    "ArrowDown" => {
329	                        e.prevent_default();
330	                        match self.history_index {
331	                            None => return false,
332	                            Some(i) if i + 1 < self.history.len() => {
333	                                self.history_index = Some(i + 1);
334	                                self.input = self.history[i + 1].clone();
335	                            }
336	                            Some(_) => {
337	                                self.history_index = None;
338	                                self.input = std::mem::take(&mut self.history_saved_input);
339	                            }
340	                        }
341	                        true
342	                    }
343	                    "Backspace" => {
344	                        e.prevent_default();
345	                        self.input.pop();
346	                        true
347	                    }
348	                    _ => {
349	                        if key.len() == 1 {
350	                            e.prevent_default();
351	                            let ch = key.chars().next().unwrap();
352	                            if ch.is_ascii_graphic() || ch == ' ' {
353	                                self.input.push(ch);
354	                                return true;
355	                            }
356	                        }
357	                        false
358	                    }
359	                }
360	            }
361	        }
362	    }
363	
364	    fn rendered(&mut self, _ctx: &Context<Self>, first_render: bool) {
365	        self.scroll_to_bottom();
366	        if (first_render || self.needs_focus)
367	            && let Some(el) = self.panel_ref.cast::<HtmlDivElement>()
368	        {
369	            let _ = el.focus();
370	            self.needs_focus = false;
371	        }
372	    }
373	
374	    fn view(&self, ctx: &Context<Self>) -> Html {
375	        let onkeydown = ctx.link().callback(Msg::KeyDown);
376	        let mode = ctx.props().display_mode;
377	
378	        html! {
379	            <div class="repl-panel" tabindex="0" {onkeydown} ref={self.panel_ref.clone()}>
380	                <div class="repl-output" ref={self.output_ref.clone()}>
381	                    { for self.output.iter().map(|line| Self::render_line(line, mode)) }
382	                    // Show partial line if the emulator is mid-output
383	                    if !self.partial_line.is_empty() {
384	                        <div class="repl-line">{ &self.partial_line }</div>
385	                    }
386	                    <div class="repl-input-line">
387	                        <span class="repl-prompt">{ PROMPT }</span>
388	                        <span class="repl-input-text">
389	                            { Self::render_segments(&prettify_line(&self.input, mode)) }
390	                        </span>
391	                        <span class="repl-cursor">{"\u{2588}"}</span>
392	                    </div>
393	                </div>
394	            </div>
395	        }
396	    }
397	}
