                        }
                        self.input.clear();
                        self.history_index = None;
                        true
                    }
                    "ArrowUp" => {
                        e.prevent_default();
                        if self.history.is_empty() {
                            return false;
                        }
                        let new_index = match self.history_index {
                            None => {
                                self.history_saved_input = self.input.clone();
                                self.history.len() - 1
                            }
                            Some(0) => return false,
                            Some(i) => i - 1,
