                        <span class="repl-prompt">{ PROMPT }</span>
                        <span class="repl-input-text">
                            { Self::render_segments(&prettify_line(&self.input, mode)) }
                        </span>
                        <span class="repl-cursor">{"\u{2588}"}</span>
                    </div>
                </div>
            </div>
        }
    }
}

